hooks.command:
node --input-type=module <<'EOF'
import { existsSync } from 'fs';
const file = JSON.parse(await new Promise(r => { let d=''; process.stdin.on('data',c=>d+=c); process.stdin.on('end',()=>r(d)); }));
if (file?.tool_input?.path?.endsWith('.js')) {
  const { execSync } = await import('child_process');
  try { execSync(`node --check ${file.tool_input.path}`, {stdio:'pipe'}); } catch(e) { console.error('Syntax error in', file.tool_input.path); process.exit(2); }
}
EOF
